class AstroidScrollEffects{constructor(options={}){this.options={mobile:false,debug:false,selectorSpeed:"[data-speed]",selectorLag:"[data-lag]",reduceMotion:true,...options};this.instances=[];this.enabled=true}log(...args){if(this.options.debug){console.log("[AstroidScrollEffects]",...args)}}init(){if(typeof gsap==="undefined"||typeof ScrollTrigger==="undefined"){console.warn("GSAP + ScrollTrigger required.");return}gsap.registerPlugin(ScrollTrigger);if(this.options.reduceMotion&&window.matchMedia("(prefers-reduced-motion: reduce)").matches){this.log("Reduced motion enabled. Effects skipped.");return}this.initParallax();this.initLag();this.bindEvents();ScrollTrigger.refresh();this.log("Initialized")}initParallax(){const items=document.querySelectorAll(this.options.selectorSpeed);items.forEach(el=>{const speed=parseFloat(el.dataset.speed||1);const distance=(1-speed)*200;const tween=gsap.fromTo(el,{y:-distance},{y:distance,ease:"none",scrollTrigger:{trigger:el,start:"top bottom",end:"bottom top",scrub:true}});this.instances.push(tween)});this.log(`Parallax: ${items.length}`)}initLag(){const items=document.querySelectorAll(this.options.selectorLag);items.forEach(el=>{const lag=parseFloat(el.dataset.lag||.3);const tween=gsap.to(el,{y:-150,ease:"none",scrollTrigger:{trigger:el,start:"top bottom",end:"bottom top",scrub:lag*3}});this.instances.push(tween)});this.log(`Lag: ${items.length}`)}refresh(){ScrollTrigger.refresh();this.log("Refreshed")}destroy(){this.instances.forEach(item=>{if(item.scrollTrigger)item.scrollTrigger.kill();item.kill()});this.instances=[];ScrollTrigger.getAll().forEach(st=>st.kill());this.unbindEvents();this.log("Destroyed")}bindEvents(){this._resizeHandler=()=>this.refresh();this._loadHandler=()=>this.refresh();window.addEventListener("resize",this._resizeHandler);window.addEventListener("load",this._loadHandler)}unbindEvents(){window.removeEventListener("resize",this._resizeHandler);window.removeEventListener("load",this._loadHandler)}}document.addEventListener("DOMContentLoaded",function(){const effects=new AstroidScrollEffects({});effects.init()});